import{_ as t,c as a,a1 as e,o as c}from"./chunks/framework.BDxlaA_J.js";const d=JSON.parse('{"title":"Phát hiện lưu lượng tấn công DoS","description":"","frontmatter":{},"headers":[],"relativePath":"vi/categories/ethical-hacking-labs/9-denial-of-service/3-Detecting-DoS-Traffic.md","filePath":"vi/categories/ethical-hacking-labs/9-denial-of-service/3-Detecting-DoS-Traffic.md"}'),s={name:"vi/categories/ethical-hacking-labs/9-denial-of-service/3-Detecting-DoS-Traffic.md"};function i(r,n,h,o,g,p){return c(),a("div",null,n[0]||(n[0]=[e(`<h1 id="phat-hien-luu-luong-tan-cong-dos" tabindex="-1">Phát hiện lưu lượng tấn công DoS <a class="header-anchor" href="#phat-hien-luu-luong-tan-cong-dos" aria-label="Permalink to &quot;Phát hiện lưu lượng tấn công DoS&quot;">​</a></h1><p>KFSensor là một hệ thống phát hiện xâm nhập (IDS) dạng honeypot dựa trên Windows. Nó hoạt động như một honeypot để thu hút và phát hiện tin tặc và worm bằng cách mô phỏng các dịch vụ hệ thống và Trojan dễ bị tổn thương. Bằng cách đóng vai trò là máy chủ mồi nhử, nó có thể chuyển hướng các cuộc tấn công khỏi hệ thống quan trọng và cung cấp mức thông tin cao hơn so với tường lửa và NIDS đơn thuần.</p><p>KFSensor dùng thử miễn phí: <a href="http://www.keyfocus.net/kfsensor/" target="_blank" rel="noreferrer">http://www.keyfocus.net/kfsensor/</a> Wireshark: <a href="https://www.wireshark.org/" target="_blank" rel="noreferrer">https://www.wireshark.org/</a></p><h3 id="muc-tieu" tabindex="-1">Mục tiêu <a class="header-anchor" href="#muc-tieu" aria-label="Permalink to &quot;Mục tiêu&quot;">​</a></h3><ul><li>Phát hiện tấn công DoS bằng KFSensor</li><li>Phân tích gói tin đến đã bắt bằng Wireshark</li></ul><h3 id="yeu-cau" tabindex="-1">Yêu cầu <a class="header-anchor" href="#yeu-cau" aria-label="Permalink to &quot;Yêu cầu&quot;">​</a></h3><ul><li>Máy ảo Windows 10</li><li>Máy ảo Windows Server 2012 hoặc 2016</li><li>Máy ảo Kali Linux</li></ul><h2 id="thiet-lap" tabindex="-1">Thiết lập <a class="header-anchor" href="#thiet-lap" aria-label="Permalink to &quot;Thiết lập&quot;">​</a></h2><ol><li><p>Cài đặt <a href="http://www.keyfocus.net/kfsensor/" target="_blank" rel="noreferrer">KFSensor</a> và <a href="https://www.wireshark.org/" target="_blank" rel="noreferrer">Wireshark</a> trên máy ảo Windows 10.</p></li><li><p>Khởi chạy KFSensor với quyền Administrator.</p></li><li><p>Nhấp vào <strong>Settings</strong> trên menu trên cùng và Set Up Wizard: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9296013460b912b31656952b31c5c8fb343b073d/kfsensor-1.png" alt="kfsensor"> Để các tùy chọn mặc định cho đến khi dừng ở tùy chọn DoS.</p></li><li><p>Chọn <strong>Cautious</strong> từ danh sách thả xuống Denial of Service Options, và chọn <strong>Enable packet dump files</strong> từ danh sách thả xuống <strong>Network Protocol Analyzer</strong>: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9296013460b912b31656952b31c5c8fb343b073d/kfsensor-2.png" alt="kfsensor2"></p></li><li><p>Nhấp next và hoàn tất wizard: <img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/9296013460b912b31656952b31c5c8fb343b073d/kfsensor-3.png" alt="kfsensor3"></p></li></ol><p>Trên panel bên trái bạn sẽ thấy biểu tượng FTP có màu xanh lá, và phần FTP trống, điều này có nghĩa là hiện tại không có lưu lượng truy cập qua cổng 21.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/d2a685936b7fe3a16bbc3f53e6a9462c0cea0477/kfsensor-4.png" alt="kfsensor4"></p><p>Bây giờ, KFSensor đã được cấu hình để phát hiện các cuộc tấn công DoS.</p><h2 id="thuc-hien-tan-cong-dos" tabindex="-1">Thực hiện tấn công DoS <a class="header-anchor" href="#thuc-hien-tan-cong-dos" aria-label="Permalink to &quot;Thực hiện tấn công DoS&quot;">​</a></h2><p>Chuyển sang Kali Linux và mở một cửa sổ terminal mới.</p><ol><li>Kiểm tra xem cổng 21 có mở không: <code>nmap -p 21 &lt;Windows 10 IP address&gt;</code></li></ol><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Starting Nmap 7.80 ( https://nmap.org ) at 2020-01-22 14:02 EST</span></span>
<span class="line"><span>Nmap scan report for 10.0.2.45</span></span>
<span class="line"><span>Host is up (0.00051s latency).</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PORT   STATE SERVICE</span></span>
<span class="line"><span>21/tcp open  ftp</span></span></code></pre></div><p><strong>Như bạn có thể thấy ở trên, cổng 21 đang mở.</strong></p><p>Hãy sử dụng cổng này để tràn ngập mục tiêu:</p><ol start="2"><li>Thực hiện <strong>SYN flooding</strong> bằng cách gõ: <code>hping3 -d 100 -S -p 21 --flood &lt;Windows 10 IP Address&gt;</code></li></ol><table tabindex="0"><thead><tr><th>Tham số</th><th>Mô tả</th></tr></thead><tbody><tr><td><code>-S</code></td><td>SYN Flooding</td></tr><tr><td><code>-p 21</code></td><td>Cổng 21</td></tr><tr><td><code>-d 100</code></td><td>Kích thước dữ liệu mỗi gói (byte)</td></tr></tbody></table><p>Sau khi nhập lệnh, chuyển sang <strong>Windows 10</strong>, quan sát thấy máy gần như bị đơ, điều này có nghĩa là tài nguyên của Windows đã bị cạn kiệt hoàn toàn. Điều này có nghĩa là cuộc tấn công DoS đang được thực hiện thành công.</p><p>Chuyển ngược lại <strong>Kali Linux</strong> và nhấn <strong>Ctrl+C</strong> để chấm dứt SYN flooding.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/69d1c60b4927909ac69784c963ad1712c5f5fe0a/kfsensor-7.png" alt="hping3-terminate"></p><h2 id="phat-hien-tan-cong-dos" tabindex="-1">Phát hiện tấn công DoS <a class="header-anchor" href="#phat-hien-tan-cong-dos" aria-label="Permalink to &quot;Phát hiện tấn công DoS&quot;">​</a></h2><p>Chuyển sang <strong>Windows 10</strong>, bây giờ bạn có thể truy cập được vào nó.</p><p>Bây giờ biểu tượng FTP trong panel bên trái chuyển sang <strong>màu đỏ</strong>, và phần FTP trong panel bên phải bị tràn ngập bởi các sự kiện.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/69d1c60b4927909ac69784c963ad1712c5f5fe0a/kfsensor-8.png" alt="kfsensor9"></p><p>Cuộn xuống và cố gắng tìm một sự kiện có tên <strong>DOS Attack</strong></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/19219e6d8c9e72aa7349794f40ecb1ad02daffbd/kfsensor-9.png" alt="kfsensor10"></p><p>Điều này kết luận rằng KFSensor đã phát hiện cuộc tấn công DoS.</p><p>Chọn một sự kiện ngẫu nhiên khác và nhấp đúp để hiển thị chi tiết sự kiện.</p><p>Trên cửa sổ Event, chứa tóm tắt sự kiện, bạn có thể thấy mức độ nghiêm trọng của sự kiện <strong>(High)</strong>, mô tả sự kiện <strong>(Syn Scan)</strong>, khách truy cập của sự kiện <strong>(địa chỉ IP của máy tấn công)</strong>, tên cảm biến <strong>(FTP)</strong>, và nhiều thông tin khác như bạn có thể thấy dưới đây.</p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/19219e6d8c9e72aa7349794f40ecb1ad02daffbd/kfsensor-10.png" alt="kfsensor11"></p><h2 id="phan-tich-packet-dump-tren-wireshark" tabindex="-1">Phân tích Packet Dump trên Wireshark <a class="header-anchor" href="#phan-tich-packet-dump-tren-wireshark" aria-label="Permalink to &quot;Phân tích Packet Dump trên Wireshark&quot;">​</a></h2><p>Tiếp theo, phân tích file packet dump chứa lưu lượng đã bắt trong cuộc tấn công DoS. KFSensor lưu file packet dump tại <strong>C:\\kfsensor\\dumps</strong> theo mặc định.</p><p>Mở Wireshark và nhấp vào <strong>File &gt; Open</strong> và mở file packet dump được lưu tại <strong>C:\\kfsensor\\dumps</strong></p><p><img src="https://gist.githubusercontent.com/Samsar4/62886aac358c3d484a0ec17e8eb11266/raw/84f8b3324442d6d26f744a9566c74dd7964bc866/kfsensor-11.png" alt="kfsensor-wireshark11"></p><p>Wireshark tải file và hiển thị chi tiết gói tin, như hình trên.</p><p>Bạn có thể phân tích các gói tin để thu thập thông tin liên quan đến header của gói tin, địa chỉ IP nguồn, và nhiều thông tin khác.</p>`,39)]))}const u=t(s,[["render",i]]);export{d as __pageData,u as default};
